from collections import deque, defaultdict

def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0

    max_num = 10**6
    spf = list(range(max_num + 1))
    for i in range(2, int(max_num**0.5) + 1):
        if spf[i] == i:
            for j in range(i * i, max_num + 1, i):
                if spf[j] == j:
                    spf[j] = i

    prime_to_indices = defaultdict(list)
    for idx, num in enumerate(nums):
        if num == 1:
            continue
        temp = num
        factors = set()
        while temp != 1:
            p = spf[temp]
            factors.add(p)
            while temp % p == 0:
                temp //= p
        for p in factors:
            prime_to_indices[p].append(idx)

    visited = [False] * n
    q = deque()
    q.append((0, 0))
    visited[0] = True

    while q:
        current_idx, steps = q.popleft()
        if current_idx == n - 1:
            return steps
        for next_idx in [current_idx - 1, current_idx + 1]:
            if 0 <= next_idx < n and not visited[next_idx]:
                visited[next_idx] = True
                q.append((next_idx, steps + 1))
        if nums[current_idx] in prime_to_indices:
            for j in prime_to_indices[nums[current_idx]]:
                if j != current_idx and not visited[j]:
                    visited[j] = True
                    q.append((j, steps + 1))
    return -1
